public int numSub(String s) {
    int mod = 1000000007;
    long result = 0;
    int count = 0;
    for (char c : s.toCharArray()) {
        count = (c == '1') ? count + 1 : 0;
        result = (result + count) % mod;
    }
    return (int)result;
}
```

